├── playwright.config.ts
├── tests/
│   └── e2e/
│       ├── login.spec.ts
│       └── product.spec.ts
├── pages/
│   ├── LoginPage.ts
│   └── ProductPage.ts
├── components/
│   ├── NavigationBar.ts
│   └── SearchWidget.ts
├── fixtures/
│   └── customFixtures.ts
├── utils/
│   └── dataGenerator.ts
├── helpers/
│   └── apiHelper.ts
└── data/
    └── testData.json
```
This structured approach ensures a highly maintainable, scalable, and efficient automation framework.

